const DEFAULT_MODELS={enabler:"anthropic/claude-3-haiku",skeptic:"anthropic/claude-3.5-sonnet",mediator:"anthropic/claude-3-opus"};async function loadSettings(){const e=await chrome.storage.sync.get(["apiKey","models","priceThreshold"]);document.getElementById("apiKey").value=e.apiKey||"",document.getElementById("priceThreshold").value=void 0!==e.priceThreshold?e.priceThreshold:50;const t=e.models||DEFAULT_MODELS;document.getElementById("modelEnabler").value=t.enabler||DEFAULT_MODELS.enabler,document.getElementById("modelSkeptic").value=t.skeptic||DEFAULT_MODELS.skeptic,document.getElementById("modelMediator").value=t.mediator||DEFAULT_MODELS.mediator}async function saveSettings(e){e.preventDefault();const t=document.getElementById("apiKey").value.trim(),s=parseFloat(document.getElementById("priceThreshold").value)||0,a={enabler:document.getElementById("modelEnabler").value,skeptic:document.getElementById("modelSkeptic").value,mediator:document.getElementById("modelMediator").value};!t||t.startsWith("sk-or-")?s<0?showStatus("Price threshold must be 0 or greater","error"):(await chrome.storage.sync.set({apiKey:t,models:a,priceThreshold:s}),showStatus("Settings saved successfully!","success")):showStatus("Please enter a valid OpenRouter API key (starts with sk-or-)","error")}async function resetSettings(){confirm("Reset all settings to defaults?")&&(await chrome.storage.sync.clear(),await loadSettings(),showStatus("Settings reset to defaults","success"))}function showStatus(e,t){const s=document.getElementById("statusMessage");s.textContent=e,s.className=`status-message ${t} show`,setTimeout(()=>{s.classList.remove("show")},3e3)}document.getElementById("settingsForm").addEventListener("submit",saveSettings),document.getElementById("resetBtn").addEventListener("click",resetSettings),loadSettings();